const raw = $input.item.json || {};
const body = raw.body != null && typeof raw.body === 'object' ? raw.body : raw;
const safe = body && typeof body === 'object' ? body : {};

const event = safe.event || '';
const messageType = safe.message_type || '';
const assignee = safe.conversation?.meta?.assignee;
const senderType = safe.conversation?.messages?.[0]?.sender?.type || '';

const isMessageCreated = event === 'message_created';
const isIncoming = messageType === 'incoming';
const isFromContact = senderType === 'contact';
const noAssignee = assignee === null || assignee === undefined;

const shouldProcess = isMessageCreated && isIncoming && isFromContact && noAssignee;

const conversationId = safe.conversation?.id?.toString() || '';
const messageId = safe.id?.toString() || '';
const content = (safe.content || '').replace(/<[^>]*>/g, '').trim();

return [{ json: {
  ...safe,
  shouldProcess,
  conversationId,
  messageId,
  content
} }];

const payload = $input.item.json.payload || [];
const origem = $('Verificar Condições1').first().json || {};
const incoming = payload
  .filter(function(m) { return m.message_type === 0; })
  .sort(function(a, b) { return a.created_at - b.created_at; });

const webhookId = String(origem.messageId || '');
const idx = incoming.findIndex(function(m) { return String(m.id) === webhookId; });
const sliceEnd = idx >= 0 ? idx + 1 : incoming.length;
const windowSize = 6;
const contextMsgs = incoming.slice(Math.max(0, sliceEnd - windowSize), sliceEnd);

const cleaned = contextMsgs
  .map(function(m) { return String(m.processed_message_content || m.content || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim(); })
  .filter(function(t) { return t.length > 0; });

const uniqueOrdered = [];
for (const t of cleaned) {
  if (!uniqueOrdered.includes(t)) uniqueOrdered.push(t);
}

const lastIncoming = contextMsgs.length ? contextMsgs[contextMsgs.length - 1] : null;
const lastId = lastIncoming ? String(lastIncoming.id) : '';
const currentUserMessage = lastIncoming
  ? String(lastIncoming.processed_message_content || lastIncoming.content || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim()
  : String(origem.content || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();

const previousMsgs = uniqueOrdered.filter(function(t) { return t !== currentUserMessage; });
const combined = uniqueOrdered.join(' | ');
const contextForAgent = previousMsgs.slice(-3).join(' | ');

const textNorm = combined.toLowerCase();
const vehicleLex = ['ducato','boxer','jumper','master','sprinter','hr','k2500','h100','daily','transit','iveco','l200','hilux','frontier','towner'];
const foundVehicles = vehicleLex.filter(function(v) { return textNorm.includes(v); });
const years = Array.from(textNorm.matchAll(/\b(19\d{2}|20\d{2})\b/g)).map(function(m) { return m[1]; });
const contextVehicleTerm = (foundVehicles.slice(-2).join(' ') + (years.length ? ' ' + years[years.length - 1] : '')).trim();

const productIntent = /(pe[cç]a|peca|c[oó]digo|precis|procur|cota|cot[eé]|pre[cç]o|valor|estoque|dispon[ií]vel|\btem\b|quero|queria|quanto|comprar|encomen)/i;
const forceCatalogSearch = productIntent.test(currentUserMessage);

return [{
  json: {
    isLastMessage: lastId === webhookId,
    lastMessageId: lastId,
    webhookMessageId: webhookId,
    combinedMessage: combined || currentUserMessage,
    currentUserMessage,
    contextForAgent,
    contextVehicleTerm,
    forceCatalogSearch,
    totalPayload: payload.length,
    contextMessageCount: uniqueOrdered.length,
    conversationId: String(origem.conversationId || '')
  }
}];

const msgNode = $('É a Última Mensagem?').first().json;
const items = $input.all().map(i => i.json);
const hasProductIntent = msgNode.forceCatalogSearch;
const hasVehicleContext = (msgNode.contextVehicleTerm || '').length > 0;

const curMsg = (msgNode.currentUserMessage || '').trim().toLowerCase();
const socialWords = ['oi','ola','bom','boa','dia','tarde','noite','tudo','bem','como','vai','obrigado','obrigada','valeu','blz','beleza','hey','hello','opa','eai','fala','salve','tchau','ate','logo','flw','ok','brigado','brigada'];
const msgTokens = curMsg.replace(/[^a-z\s]/g, '').trim().split(/\s+/).filter(function(w) { return w.length > 1; });
const isGreetingOnly = msgTokens.length > 0 && msgTokens.length <= 6 && msgTokens.every(function(w) { return socialWords.includes(w); });

const MIN_SCORE = 2.5;
const valid = items.filter(p => p && p.name && !p.error);
const relevant = valid.filter(p => typeof p.score === 'number' && p.score >= MIN_SCORE);

let catalogText = '';
if (!isGreetingOnly && relevant.length > 0) {
  const top = relevant.slice(0, 10).map(p => {
    const parts = ['- ' + p.name];
    if (p.sku) parts.push('SKU: ' + p.sku);
    if (p.manufacturer_code) parts.push('Cód Fab: ' + p.manufacturer_code);
    parts.push('Preço: ' + (p.price_brl ? 'R$ ' + p.price_brl : 'consultar vendedor'));
    parts.push(p.stock_total > 0 ? 'Disponível: Sim' : 'Disponível: Não');
    return parts.join(' | ');
  }).join('\n');
  catalogText = '\n\nResultados da busca no catálogo Wladvan:\n' + top;
} else if (!isGreetingOnly && (hasProductIntent || hasVehicleContext)) {
  catalogText = '\n\n[Catálogo consultado: nenhum produto encontrado para esta busca]';
}

return [{
  json: {
    currentUserMessage: msgNode.currentUserMessage || '',
    contextForAgent: msgNode.contextForAgent || '',
    forceCatalogSearch: hasProductIntent,
    catalogText,
    conversationId: msgNode.conversationId || ''
  }
}];

